    uint8_t velocity_offset = ((hram.ball_velocity - 1) * 2);

    cpu->c = ball_velocity_ptr_table[velocity_offset];

    update_frame_accumulator();

    cpu->a = byte_array_100b[hram.frame_accumulator & 0x07];

    cpu->a *= 4;

    //address of (byte_array_100b + cpu->a)[cpu->c];

